def f1(s, a):
    try:
        r = int(a[0]); c = int(a[1])
    except:
        return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    return s[r][c] == ${TOKEN}

def f2(s, a):
    try:
        r = int(a[0]); c = int(a[1])
    except:
        return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    for dr, dc in ${DRs}:
        nr, nc = r + dr, c + dc
        if 0 <= nr < h and 0 <= nc < w:
            if s[nr][nc] == ${TOKEN}:
                return True
    return False

def f3(s, a):
    try:
        r = int(a[0]); c = int(a[1])
    except:
        return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    for dr, dc in ${DRs}:
        for k in range(1, ${K}+1):
            nr, nc = r + dr*k, c + dc*k
            if 0 <= nr < h and 0 <= nc < w:
                if s[nr][nc] == ${TOKEN}:
                    return True
    return False
